import 'package:flutter/services.dart'; import 'package:firebase_database/firebase_database.dart'; import 'package:firebase_auth/firebase_auth.dart'; import 'package:injectable/injectable.dart'; @injectable class ClipboardSyncService { final _db = FirebaseDatabase.instance; String get _uid => FirebaseAuth.instance.currentUser?.uid ?? ''; Future<void> syncToRemote(String targetDeviceId) async { final data = await Clipboard.getData(Clipboard.kTextPlain); if (data?.text != null) await _db.ref('clipboard/$targetDeviceId').set({'text': data!.text, 'from': _uid, 'ts': ServerValue.timestamp}); } Future<String?> getRemoteClipboard() async { final snap = await _db.ref('clipboard/$_uid').get(); return snap.exists ? Map<String, dynamic>.from(snap.value as Map)['text'] as String? : null; } }